SELECT MAX(monthly_pay) AS max_monthly_payment
FROM monthly_payments
WHERE application_id = (SELECT application_id FROM loan_applications LIMIT 1);

SELECT application_id, monthly_pay, monthly_pay_per_income, payment_due_date, payment_status
FROM monthly_payments
WHERE monthly_pay_per_income BETWEEN 0.25 AND 0.5;

SELECT loan_id
FROM loan_applications
WHERE application_id = 1;

SELECT applicant_id 
FROM income_records 
WHERE coapplicant_income > 3000 AND monthly_income > 2500;

SELECT AVG(monthly_pay) 
FROM monthly_payments 
WHERE application_id = 1;
